eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   NEWS_ARTICLES: () => (/* binding */ NEWS_ARTICLES),\n/* harmony export */   getFeaturedNews: () => (/* binding */ getFeaturedNews),\n/* harmony export */   getNewsByCategory: () => (/* binding */ getNewsByCategory),\n/* harmony export */   getNewsBySlug: () => (/* binding */ getNewsBySlug)\n/* harmony export */ });\nconst NEWS_ARTICLES = [\n    {\n        id: \"1\",\n        featured: true,\n        slug: \"premier-league-ticket-prices-2025\",\n        title: \"Premier League 2024/25: How to Find the Best Ticket Deals This Season\",\n        snippet: \"With ticket prices hitting record highs, we break down which platforms offer the best value for the Premier League's biggest fixtures.\",\n        category: \"football\",\n        icon: \"⚽\",\n        author: \"Liam Hargreaves\",\n        authorAvatar: \"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=80&h=80&fit=crop&q=80\",\n        publishedAt: \"2025-02-18\",\n        readTime: 5,\n        imageUrl: \"https://images.unsplash.com/photo-1522778119026-d647f0596c20?w=1200&h=630&fit=crop&q=80\",\n        imageCaption: \"Premier League fixtures are among the most sought-after in world football. (Getty Images)\",\n        keyPoints: [\n            \"Average secondary market prices have surged by up to 22% versus two seasons ago\",\n            \"Setting price-drop alerts 6–8 weeks out remains one of the most reliable savings strategies\",\n            \"Always verify resale platforms carry STAR membership before purchasing\"\n        ],\n        metaTitle: \"Premier League 2024/25: Best Ticket Deals & Buying Guide\",\n        metaDescription: \"Discover where to find the best Premier League ticket deals this season. We compare prices across the top UK resale platforms for every big fixture.\",\n        content: [\n            {\n                h2: \"Why Premier League Ticket Prices Are at Record Highs\",\n                body: \"The 2024/25 Premier League season has seen average secondary market prices surge by as much as 22% compared to two seasons ago. Growing global demand — particularly from US and Asian fans visiting the UK — combined with a limited supply of official away allocations has created a perfect storm for resellers. High-profile fixtures such as Manchester City vs Arsenal and the North London Derby regularly command four-figure premiums on the secondary market, making savvy buying more important than ever.\"\n            },\n            {\n                h2: \"Which Platforms Offer the Best Value Right Now\",\n                body: \"Our latest price analysis across FootballTicketNet and Awin shows that prices for the same seat can differ by up to 35%. For fans on a tighter budget, setting up price-drop alerts on FootballTicketNet for dates six to eight weeks out remains one of the most reliable strategies.\"\n            },\n            {\n                h2: \"How to Time Your Purchase for Maximum Savings\",\n                body: \"Data from the last three seasons reveals a clear pricing pattern: tickets typically peak in the 48-hour window immediately after fixtures are announced, drop by roughly 15% in the following fortnight, and then spike again in the final 72 hours before kick-off as sellers panic-sell. The sweet spot for most fixtures is three to four weeks before match day. Midweek fixtures almost always come in cheaper than weekend equivalents even when the two teams are identical, so flexibility with travel is a real advantage.\"\n            },\n            {\n                h2: \"Essential Tips to Avoid Scams and Invalid Tickets\",\n                body: \"The Premier League reports that counterfeit ticket activity has increased 40% since contactless entry was introduced across all grounds. Always verify that a resale platform is a member of the Society of Ticket Agents and Retailers (STAR) before buying. Look for listings that include a visible barcode transfer or mobile ticket delivery to your registered email — postal paper tickets sold days before a match are a significant red flag. If a deal looks dramatically cheaper than every other listing, trust your instincts and walk away.\"\n            }\n        ]\n    },\n    {\n        id: \"2\",\n        featured: true,\n        slug: \"cheltenham-festival-guide-2025\",\n        title: \"Cheltenham Festival 2025: Complete Ticket Buying Guide\",\n        snippet: \"Everything you need to know about buying Cheltenham Festival tickets — from Champion Day to Gold Cup Day — and where to find the best prices.\",\n        category: \"horse-racing\",\n        icon: \"\\uD83C\\uDFC7\",\n        author: \"Tara Whitfield\",\n        authorAvatar: \"https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=80&h=80&fit=crop&q=80\",\n        publishedAt: \"2025-02-15\",\n        readTime: 7,\n        imageUrl: \"https://images.unsplash.com/photo-1598032895397-b9472444bf93?w=1200&h=630&fit=crop&q=80\",\n        imageCaption: \"Cheltenham Festival draws over 250,000 racegoers across the four-day meeting. (Getty Images)\",\n        keyPoints: [\n            \"Gold Cup Day hospitality packages sell out up to 12 months in advance\",\n            \"Prices on the secondary market soften 3 weeks before for Wednesday and Thursday\",\n            \"Official coach packages from London and Birmingham can offer better overall value\"\n        ],\n        metaTitle: \"Cheltenham Festival 2025: Complete Ticket Buying Guide\",\n        metaDescription: \"Your complete guide to buying Cheltenham Festival 2025 tickets. Compare Champion Day, Gold Cup Day and hospitality packages to get the best price.\",\n        content: [\n            {\n                h2: \"Understanding the Four Days of the Festival\",\n                body: \"Cheltenham Festival spans four extraordinary days in March, each with its own identity. Champion Day (Tuesday) draws the largest crowds, headlined by the Champion Hurdle, and is consistently the most expensive day on the resale market. Ladies Day (Wednesday) blends fashion with serious racing. St Patrick's Thursday brings a festive Irish contingent and fierce demand for Arkle Chase tickets. Gold Cup Friday is the pinnacle — the Gold Cup itself is Europe's most prestigious steeplechase and hospitality packages for this day are often sold out 12 months in advance.\"\n            },\n            {\n                h2: \"Official Versus Secondary Market: When to Choose Each\",\n                body: \"The Jockey Club releases official tickets in phases from October onward, and General Admission for Tuesday and Friday typically sells out within weeks. If you miss the official window, the secondary market becomes your only option. For General Admission on Wednesday and Thursday, prices on resale platforms often track only slightly above face value up to three weeks before the event, making late purchases viable. Grandstand Reserved and Club Enclosure tickets, however, command a steep premium whenever they appear secondhand — budget at least 60% above face value for peak days.\"\n            },\n            {\n                h2: \"Hospitality Packages: Are They Worth the Investment?\",\n                body: \"Private boxes and hospitality suites at Cheltenham start at around \\xa3350 per person and can exceed \\xa31,200 for Gold Cup Friday packages with a trackside view. For groups of four or more, the per-head cost of a hospitality package can actually compare favourably to buying premium grandstand seats individually on the secondary market while also including food, drink, and a dedicated betting concierge. The key is to book directly through official hospitality partners rather than third-party brokers who frequently add margins of 20% or more.\"\n            },\n            {\n                h2: \"Practical Tips for Getting There and Making the Most of Your Day\",\n                body: \"Cheltenham Racecourse is located on the outskirts of Cheltenham town, roughly a 20-minute taxi ride from Cheltenham Spa rail station. Official coach services run from Birmingham New Street and London Victoria and are included in some ticket packages. Parking on-site is limited and must be pre-booked. Arrive at least 90 minutes before the first race to soak up the atmosphere, explore the parade ring, and queue for the best trackside positions in the General Admission areas.\"\n            }\n        ]\n    },\n    {\n        id: \"3\",\n        featured: true,\n        slug: \"wimbledon-ballot-tips\",\n        title: \"5 Tips for the Wimbledon Ballot and When to Use Resale Sites\",\n        snippet: \"Missed the Wimbledon ballot? Don't panic. We explain when the secondary market becomes your best option and how to avoid overpaying.\",\n        category: \"tennis\",\n        icon: \"\\uD83C\\uDFBE\",\n        author: \"Chloe Drummond\",\n        authorAvatar: \"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=80&h=80&fit=crop&q=80\",\n        publishedAt: \"2025-02-12\",\n        readTime: 4,\n        imageUrl: \"https://images.unsplash.com/photo-1554068865-24cecd4e34b8?w=1200&h=630&fit=crop&q=80\",\n        imageCaption: \"Centre Court at Wimbledon remains the most prestigious tennis venue in the world. (Getty Images)\",\n        keyPoints: [\n            \"Fewer than 1 in 12 ballot applicants receive tickets — apply every year\",\n            \"Centre Court prices historically drop 18% after a top seed is eliminated\",\n            \"The Wimbledon Queue distributes ~500 Centre Court tickets daily during the Championships\"\n        ],\n        metaTitle: \"Wimbledon Ballot Tips 2025 & Best Resale Sites Compared\",\n        metaDescription: \"Learn how to maximise your chances in the Wimbledon public ballot and discover the best resale platforms to use if you miss out on official tickets.\",\n        content: [\n            {\n                h2: \"How the Wimbledon Public Ballot Actually Works\",\n                body: \"The All England Club's public ballot opens each year between 30 July and 31 December for the following summer's Championships. Applicants must register individually — joint applications are not permitted — and successful ballots are announced the following April. Each successful applicant receives a maximum of two tickets for a single day session on Centre Court, Court 1, or Court 2. The ballot is heavily oversubscribed: in recent years fewer than 1 in 12 applicants have been successful, which is why so many fans turn to the secondary market.\"\n            },\n            {\n                h2: \"Five Tips to Maximise Your Ballot Chances\",\n                body: \"First, register early — the system confirms each registration by email and early registrants have historically had a marginally higher success rate. Second, use a personal email address you check regularly, as ballot results are dispatched quickly and unclaimed allocations are re-drawn. Third, apply for grounds passes as a backup — they are separate from the Centre Court ballot and often overlooked. Fourth, check that your postal address is correct; mismatched addresses have caused tickets to be issued and not received. Fifth, register every year: the ballot is random but persistent applicants statistically receive tickets every five to seven years.\"\n            },\n            {\n                h2: \"When the Secondary Market Is Your Best Option\",\n                body: \"If you miss the ballot, resale platforms become essential. The official Wimbledon Debenture Holders scheme releases a small number of Centre Court tickets through the official resale portal, and these carry a price premium but are guaranteed authentic. For broader availability, FootballTicketNet and Awin both list verified e-transfer tickets with buyer guarantees. Research shows that prices for Centre Court day sessions drop by an average of 18% in the 48 hours after a high-profile player is eliminated — so flexibility to watch the tournament rather than a specific match pays off handsomely.\"\n            },\n            {\n                h2: \"Queue Tickets: The Hidden Gem Most Fans Miss\",\n                body: \"The famous Wimbledon Queue offers approximately 500 Centre Court tickets and 500 Court 1 tickets each day through the physical queuing system. Grounds passes, which grant access to the outside courts, are also available and provide an atmospheric and affordable way to experience the Championships. Arriving before 6 am dramatically improves your chances of securing Centre Court queue tickets; many seasoned fans camp overnight. The Queue is free to join and stewarded by the All England Club, making it one of the safest and most authentic ways to experience Wimbledon without paying secondary market prices.\"\n            }\n        ]\n    },\n    {\n        id: \"4\",\n        slug: \"f1-silverstone-hospitality-guide\",\n        title: \"British GP 2025: Grandstand vs Paddock Club — Is the Upgrade Worth It?\",\n        snippet: \"We compare Silverstone's general admission, grandstand, and Paddock Club hospitality packages to help you decide what's worth your money.\",\n        category: \"formula-1\",\n        icon: \"\\uD83C\\uDFCE️\",\n        author: \"Owen Castellano\",\n        authorAvatar: \"https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=80&h=80&fit=crop&q=80\",\n        publishedAt: \"2025-02-10\",\n        readTime: 6,\n        imageUrl: \"https://images.unsplash.com/photo-1541773367383-abb53af2b1d5?w=1200&h=630&fit=crop&q=80\",\n        imageCaption: \"The British Grand Prix at Silverstone is one of the highlights of the Formula 1 calendar. (Getty Images)\",\n        keyPoints: [\n            \"The Paddock Club starts at ~\\xa31,700 per race-day pass — ten times more than grandstand\",\n            \"The Hangar Straight stand offers some of the longest sightlines of any seat at Silverstone\",\n            \"Three-day grandstand passes save an average of 22% vs buying days individually\"\n        ],\n        metaTitle: \"British GP 2025: Silverstone Grandstand vs Paddock Club Guide\",\n        metaDescription: \"Is the Silverstone Paddock Club worth the price? We break down every ticket category for the 2025 British Grand Prix to help you choose wisely.\",\n        content: [\n            {\n                h2: \"Breaking Down Every Silverstone Ticket Category\",\n                body: \"Silverstone offers five main ticket tiers for the British Grand Prix. General Admission (from \\xa385/day) grants access to the infield and designated standing areas but no fixed seat. Grandstand tickets (from \\xa3160/day) cover named stands including Copse, Maggotts, and the Pit Straight. Club Corner and Wing Hospitality suites (from \\xa3350/day) add catering and covered seating. The Formula 1 Paddock Club, the sport's premier hospitality product, starts at approximately \\xa31,700 for a race-day pass and represents the highest tier available to the public.\"\n            },\n            {\n                h2: \"Which Grandstand Gives the Best View of the Action?\",\n                body: \"The Hangar Straight grandstand offers one of the longest sustained views of any seat at Silverstone — you can watch cars accelerate from Stowe corner all the way down to Vale — and it remains one of the best-value named stands. The Pit Straight grandstand is iconic but largely obscured by the pit wall gantry unless you are in the upper tiers. For overtaking action, Club Corner and Brooklands are statistically the most active braking zones. If you plan to attend across the full weekend, buying a three-day grandstand pass saves an average of 22%.\"\n            },\n            {\n                h2: \"What the Paddock Club Actually Includes (and What It Doesn't)\",\n                body: \"The Formula 1 Paddock Club hospitality is located directly above the pit lane and includes: a reserved seat in a glass-fronted suite, \\xe0 la carte dining from a Michelin-trained kitchen, unlimited premium bar, a paddock walkabout pass, and opportunities to view garages during designated windows. What it does not include: a guarantee of driver meet-and-greets or pit lane access during sessions. For die-hard fans wanting the closest possible connection to the teams, it remains unmatched; for those primarily watching the race, a grandstand at one-tenth of the price delivers more raw racing drama.\"\n            },\n            {\n                h2: \"How to Book Silverstone Tickets and Avoid the Resale Premium\",\n                body: \"Official Silverstone tickets for the British Grand Prix go on general sale in October each year. Demand for Race Day grandstands is particularly acute and they frequently sell out within hours. Setting up an account in advance and being logged in at the exact sale time is essential. For those who miss general sale, the official Silverstone Ticket Exchange allows fans to list unwanted tickets at face value — far safer than third-party platforms where premiums of 50–80% are common. If using a secondary platform, verify the listing includes mobile transfer delivery tied to your name.\"\n            }\n        ]\n    },\n    {\n        id: \"5\",\n        slug: \"boxing-ticket-buying-tips\",\n        title: \"How to Buy Boxing Tickets: Avoiding Scams and Finding Real Value\",\n        snippet: \"Boxing ticket scams are on the rise. Here's our guide to the safest platforms, how to spot a fake ticket, and where to find the best prices.\",\n        category: \"boxing\",\n        icon: \"\\uD83E\\uDD4A\",\n        author: \"Dexter Okafor\",\n        authorAvatar: \"https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=80&h=80&fit=crop&q=80\",\n        publishedAt: \"2025-02-08\",\n        readTime: 5,\n        imageUrl: \"https://images.unsplash.com/photo-1549719386-74dfcbf7dbed?w=1200&h=630&fit=crop&q=80\",\n        imageCaption: \"Major boxing events at the O2 and AO Arena sell out within minutes of going on sale. (Getty Images)\",\n        keyPoints: [\n            \"Boxing accounted for 31% of all sports ticket fraud reported in the UK last year\",\n            \"Never pay via bank transfer, PayPal F&F, or crypto — no purchase protection applies\",\n            \"Prices typically bottom out around one week before fight night on premium ringside seats\"\n        ],\n        metaTitle: \"Boxing Ticket Buying Guide 2025: Avoid Scams & Find Best Prices\",\n        metaDescription: \"Stay safe when buying boxing tickets in 2025. Our expert guide covers the top platforms, red flags to watch for, and how to find the best-value seats.\",\n        content: [\n            {\n                h2: \"Why Boxing Is the Sport Most Targeted by Ticket Fraudsters\",\n                body: \"According to Action Fraud UK, boxing events accounted for 31% of all sports ticket fraud reported in the last 12 months — more than any other single sport. The primary reason is the concentration of large, one-night-only events with massive public demand and a relatively short promotional window. Fights like Anthony Joshua's rematches and Tyson Fury's heavyweight bouts generate millions of social media impressions within minutes of announcement, and fraudsters exploit the urgency by listing fake tickets before official sales even open.\"\n            },\n            {\n                h2: \"How to Spot a Fraudulent Boxing Ticket Listing\",\n                body: \"Several warning signs are consistent across fraudulent listings. Price anomalies are the most common indicator: if a ringside seat is listed at 40% below every other platform, the ticket is almost certainly counterfeit or the seller is phishing for payment details. Be extremely cautious of sellers asking for payment via bank transfer, PayPal Friends and Family, or cryptocurrency — none offer purchase protection. Screenshots of PDF tickets sent via WhatsApp are easily duplicated and can be sold hundreds of times. Always insist on QR-code mobile transfer through a named platform.\"\n            },\n            {\n                h2: \"The Safest Platforms for Buying Boxing Tickets in the UK\",\n                body: \"For major UK promotions (Matchroom, Queensberry), the safest starting point is always the official promoter's ticketing partner — typically AXS or FootballTicketNet. Both operate verified transfer systems that link tickets to the buyer's account and are unduplicatable. For the secondary market, FootballTicketNet and Awin both offer money-back guarantees if tickets are invalid at entry.\"\n            },\n            {\n                h2: \"Getting the Best Price: Timing and Strategy\",\n                body: \"Boxing ticket prices follow a distinctive pattern driven by fight announcements and media cycles. The first 24 hours after an announcement are always the most expensive as demand spikes before supply adjusts. Prices typically soften 10–14 days post-announcement as initial urgency fades. For undercard and non-title fights, checking official channels on the afternoon before the event often reveals last-minute face-value releases. For premium ringside seats at major shows, prices historically bottom out around one week before fight night as unsold premium inventory gets marked down aggressively.\"\n            }\n        ]\n    },\n    {\n        id: \"6\",\n        slug: \"cricket-test-match-best-seats\",\n        title: \"England Cricket 2025: The Best Seats at Lord's, The Oval, and Edgbaston\",\n        snippet: \"Which end is best for watching Test cricket? Our ground-by-ground breakdown of the best viewing positions and how to book them.\",\n        category: \"cricket\",\n        icon: \"\\uD83C\\uDFCF\",\n        author: \"Anika Sharma\",\n        authorAvatar: \"https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=80&h=80&fit=crop&q=80\",\n        publishedAt: \"2025-02-05\",\n        readTime: 6,\n        imageUrl: \"https://images.unsplash.com/photo-1531415074968-036ba1b575da?w=1200&h=630&fit=crop&q=80\",\n        imageCaption: \"Lord's Cricket Ground in St John's Wood is the spiritual home of cricket worldwide. (Getty Images)\",\n        keyPoints: [\n            \"County membership provides priority booking windows of up to 4 weeks before general sale\",\n            \"The Eric Hollies Stand at Edgbaston consistently sells out first — book immediately on release\",\n            \"Day five Edgbaston tickets are sometimes offered free if the match reaches a likely conclusion early\"\n        ],\n        metaTitle: \"Best Seats for Test Cricket 2025: Lord's, The Oval & Edgbaston Guide\",\n        metaDescription: \"Find the best seats for England Test cricket at Lord's, The Oval, and Edgbaston in 2025. Ground-by-ground breakdown with booking tips and pricing.\",\n        content: [\n            {\n                h2: \"Lord's Cricket Ground: Where to Sit for the Full Experience\",\n                body: \"Lord's is unlike any other cricket ground in the world, and choosing where to sit requires understanding its unique character. The Compton Stand offers the purest cricket view with the Pavilion directly behind the bowler's arm from the Pavilion End — ideal for reading line and length. The Grandstand and Edrich Stand provide a broader panoramic view at a slightly higher price point. The Warner Stand is popular for its central position but can be impacted by the famous Lord's slope which tilts the whole playing surface by 2.5 metres. Avoid the Nursery End upper tier if you prioritise an unobstructed view of the iconic Pavilion backdrop.\"\n            },\n            {\n                h2: \"The Oval: Best Stands for Atmosphere and Visibility\",\n                body: \"The Kia Oval in Kennington, London is a ground where the atmosphere consistently outperforms expectations for a city venue. The OCS Stand runs along the pavilion side and offers some of the best sightlines in English cricket from the middle and upper tiers. For those who prefer a livelier atmosphere, the Bedser Stand opposite fills quickly with a knowledgeable crowd and is cheaper than the OCS equivalent. The most memorable seats in the ground are in the lower Pavilion, directly behind the bowler's arm — but these are members-only for the first three days of each Test.\"\n            },\n            {\n                h2: \"Edgbaston: The Loudest Ground in England\",\n                body: \"Edgbaston in Birmingham has cemented its reputation as England's most vocal Test cricket venue, with the Eric Hollies Stand generating an atmosphere that commentators regularly compare to a football ground. Seats in the Eric Hollies Stand are the cheapest at the ground, extremely popular, and frequently sell out first — book as soon as they go on sale. For families, the Raglan Suite end offers covered seating and clearer sightlines without the boisterous element. The pavilion stands offer outstanding views down the pitch and are the choice of the ground's most serious cricket watchers.\"\n            },\n            {\n                h2: \"How to Book England Cricket Tickets and Avoid Common Pitfalls\",\n                body: \"England home Test tickets are sold exclusively through the ECB and the host county club. Membership of the host county (Middlesex for Lord's, Surrey for The Oval, Warwickshire for Edgbaston) provides priority booking windows of up to four weeks before general sale — for major series such as the Ashes, this is often the only viable route to sought-after seats. General sale dates are announced via the ECB website in the autumn. On the secondary market, FootballTicketNet and Awin carry legitimate resale inventory, but premiums of 80–120% above face value are common for Ashes Tests. Prices tend to soften only in the final week before each Test day.\"\n            }\n        ]\n    }\n];\nconst getNewsBySlug = (slug)=>NEWS_ARTICLES.find((a)=>a.slug === slug);\nconst getFeaturedNews = ()=>NEWS_ARTICLES.filter((a)=>a.featured === true).slice(0, 3);\nconst getNewsByCategory = (category)=>category === \"all\" ? NEWS_ARTICLES : NEWS_ARTICLES.filter((a)=>a.category === category);\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/lib/data/news.ts\n");

